// 1. Fuentes de datos limpias (usando el método seguro de n8n)
const modalityCovers = $("Clean covers and modalities").all().map(item => item.json);
const optionalCovers = $("Clean Optional Covers").all().map(item => item.json);

// 2. Tuning y otros
const tuningRaw = $("Extract from Tuning").first().json;
const actualTuningContent = tuningRaw.data ? tuningRaw.data : tuningRaw;
const tuningSimplified = Object.keys(actualTuningContent).map(key => {
  const item = actualTuningContent[key];
  return {
    key: key,
    label: (item && item.label) ? item.label : 'Sin etiqueta'
  };
});

// 3. Empaquetamos todo en un único ítem de salida estructurado correctamente
return [
  {
    json: {
      context: {
        data: {
          modalities: modalityCovers,
          optionals: optionalCovers,
          tuning: tuningSimplified,
          risk: $("Extract from ramo").first().json
        },
        instructions: $("Extract from modelo comparativa").first().json.text,
        configuration: {
          product_company_id: $("On form submission").first().json?.["Product Company Id"] || 235
        }
      }
    },
    pairedItem: {
      item: 0
    }
  }
];

// 1. Obtenemos todos los items que vienen del nodo de Google Sheets
const rawItems = $input.all();

// 2. Filtramos para quitar la primera fila (la que tiene los nombres de las modalidades)
// y nos aseguramos de procesar solo filas que tengan un ID de cobertura (col_1)
const filteredRows = rawItems.filter(item => {
  const row = item.json;
  return row.row_number > 2 && row.col_1 !== "" && row.col_1 !== undefined;
});

// 3. Transformamos cada fila al formato optimizado
return filteredRows.map(item => {
  const row = item.json;

  const formattedCover = {
    cover_id: parseInt(row.col_1),
    cover_name: row.col_2,
    modalities: {}
  };

  // Recorremos todas las llaves del objeto original
  Object.keys(row).forEach(key => {
    // Si la llave es un número (ID de modalidad), la añadimos al objeto modalities
    // Excluimos las columnas de control
    if (!isNaN(key) && key !== "col_1" && key !== "col_2" && key !== "row_number") {
      // Solo añadimos la modalidad si tiene texto (está incluida)
      const content = row[key] ? row[key].trim() : "";
      if (content !== "" && content.toLowerCase() !== "sin cobertura") {
        formattedCover.modalities[key] = content;
      }
    }
  });

  return { json: formattedCover };
});

// 1. Traemos los datos del nodo "Clean covers and modalities"
// Esto funciona como un diccionario para buscar IDs por nombre de cobertura
const cleanModalities = $("Clean covers and modalities").all();

// 2. Traemos los datos de la entrada actual (la hoja de opcionales)
const rawOptionals = $input.all();

// 3. Procesamos cada fila de la hoja de opcionales
return rawOptionals.map(item => {
  const row = item.json;

  // Extraemos el nombre del epígrafe que viene en el Excel
  const nombreEpigrafeExcel = row["EPÍGRAFE EN EL QUE SE DEBE INCLUIR"];

  // BUSQUEDA: Buscamos en la lista de modalidades limpias cuál coincide con ese nombre
  // Usamos .find() para encontrar el objeto que tenga el mismo 'cover_name'
  const coverMatch = cleanModalities.find(modalidad => 
    modalidad.json.cover_name === nombreEpigrafeExcel
  );

  // 4. Devolvemos el objeto limpio y "traducido"
  return {
    json: {
      cover_name: row["COBERTURA OPCIONAL"],
      text_content: row["TEXTO QUE SE DEBE INCLUIR"] ? row["TEXTO QUE SE DEBE INCLUIR"].trim() : "",
      // Si encontramos coincidencia, ponemos el ID (ej: 15), si no, ponemos null
      parent_cover_id: coverMatch ? coverMatch.json.cover_id : null
    }
  };
});

// 1. Obtenemos el contexto y los mappings usando el nombre real del nodo
const context = $("build agents context").first().json.context;
const mappings = $("Mapping coberturas opcionales y tuning").first().json.output.mappings;

// 2. Procesamos Coberturas por Modalidad
const modalityCovers = context.data.modalities.map(row => {
  return {
    source_type: 'modality',
    cover_id: row.cover_id, // Aquí ya se llamaba cover_id
    cover_name: row.cover_name,
    modalities: row.modalities 
  };
});

// 3. Procesamos Coberturas Opcionales
const optionalCovers = context.data.optionals.map(row => {
  // Buscamos la tuning_key en los mappings
  const mapping = mappings.find(m => m.excel_name === row.cover_name) || {};

  return {
    source_type: 'optional',
    // CORRECCIÓN: Usamos parent_cover_id que es el nombre que viene del nodo de limpieza
    cover_id: row.parent_cover_id, 
    cover_name: row.cover_name,
    text_content: row.text_content,
    tuning_key: mapping.tuning_key || "NOT_FOUND"
  };
});

// 4. Devolvemos el array directamente para que n8n lo reconozca como múltiples items
return [...modalityCovers, ...optionalCovers];

// 1. Accedemos a la ruta específica donde Google guarda el texto
// El texto viene en: content -> parts -> primer elemento -> text
const rawText = $json.content.parts[0].text;

try {
  // 2. Quitamos espacios en blanco y convertimos el texto en un Array real
  const cleanJson = JSON.parse(rawText.trim());

  // 3. Devolvemos el array. n8n automáticamente creará un item por cada objeto
  return cleanJson;
} catch (e) {
  // Si algo falla (ej: Gemini devolvió texto en vez de JSON), capturamos el error
  return [{
    error: "No se pudo parsear el JSON",
    mensaje: e.message,
    lo_que_llego: rawText
  }];
}

// 1. Obtenemos el diccionario del nodo "Extract from Tuning"
const tuningMap = $("Extract from Tuning").first().json.data;

// 2. Obtenemos los datos de la cobertura actual (del Loop)
const item = $json;
const key = item.tuning_key;

// 3. Buscamos la definición técnica del campo
const fieldDef = tuningMap ? tuningMap[key] : null;

let tuningMetadata = null;

if (fieldDef) {
  // Inicializamos el objeto con lo básico
  tuningMetadata = {
    type: fieldDef.type,
    label: fieldDef.label
  };

  // 4. Lógica de mejora: solo incluimos 'options' si tienen contenido
  const items = (fieldDef.options && fieldDef.options[0]) ? fieldDef.options[0].items : [];

  if (items && items.length > 0) {
    tuningMetadata.options = items;
  }
}

// 5. Limpieza de texto para el text_content
if (item.text_content) {
  item.text_content = item.text_content
    .replace(/[\r\n]+/g, ' ')
    .replace(/\s\s+/g, ' ')
    .trim();
}

// 6. Devolvemos el objeto enriquecido
return {
  ...item,
  tuning_metadata: tuningMetadata
};

const markdown = $json.document.md_content || '';

// Eliminar cualquier imagen embebida base64
const cleaned = markdown.replace(
  /!\[.*?\]\(data:image\/[\s\S]*?\)/gm,
  ''
);

return [{
  json: {
    markdown: cleaned
  }
}];

const markdown = $json.markdown || '';

const regex = /^##\s+(Artículo\s+.*|Artículo Preliminar.*)/gmi;

const matches = [...markdown.matchAll(regex)];

const results = [];

// --------------------------------------------------
// BLOQUE INICIAL (tablas + índice + esquemas)
// --------------------------------------------------

if (matches.length > 0 && matches[0].index > 0) {

  const introContent = markdown
    .slice(0, matches[0].index)
    .trim();

  if (introContent.length > 1000) {

    results.push({
      json: {
        title: 'INTRO_AND_TABLES',
        content: introContent,
        length: introContent.length
      }
    });

  }
}

// --------------------------------------------------
// ARTÍCULOS
// --------------------------------------------------

for (let i = 0; i < matches.length; i++) {

  const start = matches[i].index;

  const end = matches[i + 1]
    ? matches[i + 1].index
    : markdown.length;

  const content = markdown
    .slice(start, end)
    .trim();

  if (content.length < 1000) continue;

  results.push({
    json: {
      title: matches[i][1].trim(),
      content,
      length: content.length
    }
  });
}

return results;

const riskSchema = $("Extract from ramo").first().json;

return items.map(item => {

  return {
    json: {
      ...item.json,
      riskSchema
    }
  };

});

return items.filter(item =>
  item.json.title === 'Artículo 3º Garantías de daños consecuenciales'
);

const raw = $json.text || '[]';

// Elimina bloques markdown
const cleaned = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (err) {

  return [
    {
      json: {
        error: true,
        message: err.message,
        raw: cleaned
      }
    }
  ];
}

// Devuelve cada regla como item independiente
return parsed.map(rule => ({
  json: rule
}));
